{
  "name": "NdraaStep - Futuristic Sneaker Marketplace",
  "description": "A premium, multi-brand sneaker experience platform with a high-end futuristic digital showroom aesthetic, featuring smooth transitions and advanced micro-interactions.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import { HashRouter } from 'react-router-dom';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <HashRouter>
      <App />
    </HashRouter>
  </React.StrictMode>
);

export interface Product {
  id: string;
  name: string;
  brand: string;
  price: number;
  image: string;
  description: string;
  color: string;
  limited?: boolean;
  releaseDate?: string;
  category: 'Men' | 'Women' | 'Unisex';
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Brand {
  id: string;
  name: string;
  logo: string;
  banner: string;
  story: string;
  themeColor: string;
  accentColor: string;
}

export type PageType = 'home' | 'shop' | 'brands' | 'new' | 'limited' | 'promo' | 'community';

import React, { useState, useEffect, useRef } from 'react';
import { Routes, Route, useLocation, useNavigate } from 'react-router-dom';
import { AnimatePresence, motion } from 'framer-motion';
import { ShoppingCart, Heart, Menu, X, ArrowRight, Github, Twitter, Instagram, Globe } from 'lucide-react';
import Navbar from './components/Navbar';
import CartDrawer from './components/CartDrawer';
import Home from './pages/Home';
import Shop from './pages/Shop';
import Brands from './pages/Brands';
import BrandDetail from './pages/BrandDetail';
import NewRelease from './pages/NewRelease';
import { Product, CartItem } from './types';
import { PRODUCTS } from './data';

const App: React.FC = () => {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [wishlist, setWishlist] = useState<string[]>([]);
  const [mousePos, setMousePos] = useState({ x: 0, y: 0 });
  const location = useLocation();
  const navigate = useNavigate();

  // Scroll Progress
  const [scrollProgress, setScrollProgress] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
      const winScroll = document.body.scrollTop || document.documentElement.scrollTop;
      const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;
      const scrolled = (winScroll / height) * 100;
      setScrollProgress(scrolled);
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      setMousePos({ x: e.clientX, y: e.clientY });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item
    ));
  };

  const toggleWishlist = (id: string) => {
    setWishlist(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
  };

  return (
    <div className="relative min-h-screen selection:bg-cyan-500 selection:text-white">
      {/* Scroll Progress Bar */}
      <div 
        className="fixed top-0 left-0 h-[2px] bg-cyber-gradient z-[100] transition-all duration-300"
        style={{ width: `${scrollProgress}%` }}
      />

      {/* Custom Cursor Glow */}
      <div 
        className="custom-cursor" 
        style={{ left: mousePos.x, top: mousePos.y }}
      />

      <Navbar cartCount={cart.reduce((acc, i) => acc + i.quantity, 0)} onCartOpen={() => setIsCartOpen(true)} />

      <AnimatePresence mode="wait">
        <motion.main
          key={location.pathname}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          exit={{ opacity: 0, y: -20 }}
          transition={{ duration: 0.5, ease: [0.22, 1, 0.36, 1] }}
          className="pt-20 pb-20"
        >
          <Routes location={location}>
            <Route path="/" element={<Home onAddToCart={addToCart} />} />
            <Route path="/shop" element={<Shop onAddToCart={addToCart} />} />
            <Route path="/brands" element={<Brands />} />
            <Route path="/brands/:brandId" element={<BrandDetail onAddToCart={addToCart} />} />
            <Route path="/new-release" element={<NewRelease onAddToCart={addToCart} />} />
            <Route path="/limited" element={<Shop onAddToCart={addToCart} filterLimited={true} />} />
            <Route path="/promo" element={<Home onAddToCart={addToCart} />} />
            <Route path="/community" element={<Home onAddToCart={addToCart} />} />
          </Routes>
        </motion.main>
      </AnimatePresence>

      <CartDrawer 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)}
        items={cart}
        onRemove={removeFromCart}
        onUpdateQuantity={updateQuantity}
      />

      {/* Footer */}
      <footer className="bg-[#080808] border-t border-white/5 py-20 px-6 lg:px-20 relative overflow-hidden">
        <div className="absolute top-0 left-1/2 -translate-x-1/2 w-full h-px bg-gradient-to-r from-transparent via-cyan-500 to-transparent opacity-20" />
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-4 gap-12 relative z-10">
          <div className="space-y-6">
            <h2 className="text-3xl font-black font-orbitron tracking-tighter bg-clip-text text-transparent bg-cyber-gradient">
              NDRAASTEP
            </h2>
            <p className="text-gray-400 text-sm leading-relaxed max-w-xs">
              Defining the next generation of footwear. Not just a marketplace, a digital showroom for the bold.
            </p>
            <div className="flex gap-4">
              {[Twitter, Github, Instagram, Globe].map((Icon, idx) => (
                <a key={idx} href="#" className="w-10 h-10 rounded-full bg-white/5 flex items-center justify-center hover:bg-cyan-500/20 hover:text-cyan-400 transition-all border border-white/10">
                  <Icon size={18} />
                </a>
              ))}
            </div>
          </div>
          <div>
            <h3 className="font-orbitron font-bold mb-6 text-sm tracking-widest text-gray-200">EXPLORE</h3>
            <ul className="space-y-4 text-gray-500 text-sm">
              <li><a href="#" className="hover:text-cyan-400 transition-colors">Digital Showroom</a></li>
              <li><a href="#" className="hover:text-cyan-400 transition-colors">Drops Calendar</a></li>
              <li><a href="#" className="hover:text-cyan-400 transition-colors">Verification Lab</a></li>
              <li><a href="#" className="hover:text-cyan-400 transition-colors">Partnerships</a></li>
            </ul>
          </div>
          <div>
            <h3 className="font-orbitron font-bold mb-6 text-sm tracking-widest text-gray-200">SUPPORT</h3>
            <ul className="space-y-4 text-gray-500 text-sm">
              <li><a href="#" className="hover:text-cyan-400 transition-colors">Shipping Hub</a></li>
              <li><a href="#" className="hover:text-cyan-400 transition-colors">Returns & Claims</a></li>
              <li><a href="#" className="hover:text-cyan-400 transition-colors">Size Guide</a></li>
              <li><a href="#" className="hover:text-cyan-400 transition-colors">FAQ</a></li>
            </ul>
          </div>
          <div>
            <h3 className="font-orbitron font-bold mb-6 text-sm tracking-widest text-gray-200">JOIN THE TECH</h3>
            <div className="relative group">
              <input 
                type="email" 
                placeholder="Enter Neural ID (Email)" 
                className="w-full bg-white/5 border border-white/10 px-4 py-3 rounded-lg focus:outline-none focus:border-cyan-500/50 transition-all text-sm pr-12"
              />
              <button className="absolute right-2 top-1/2 -translate-y-1/2 text-cyan-500 hover:text-cyan-400 transition-colors">
                <ArrowRight size={20} />
              </button>
            </div>
            <p className="text-[10px] text-gray-600 mt-3 font-orbitron">ENCRYPTED TRANSMISSION SECURE</p>
          </div>
        </div>
        <div className="max-w-7xl mx-auto pt-20 border-t border-white/5 mt-20 flex flex-col md:row items-center justify-between text-[10px] text-gray-600 font-orbitron tracking-[0.2em]">
          <p>© 2024 NDRAASTEP INC. ALL PROTOCOLS RESERVED.</p>
          <div className="flex gap-6 mt-4 md:mt-0">
            <a href="#">PRIVACY_POLICY</a>
            <a href="#">TERMS_OF_SERVICE</a>
            <a href="#">SYSTEM_STATUS: ONLINE</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { NavLink, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { ShoppingCart, Search, User } from 'lucide-react';

interface NavbarProps {
  cartCount: number;
  onCartOpen: () => void;
}

const Navbar: React.FC<NavbarProps> = ({ cartCount, onCartOpen }) => {
  const [isSearchOpen, setIsSearchOpen] = useState(false);

  const menuItems = [
    { label: 'Home', path: '/' },
    { label: 'Shop All', path: '/shop' },
    { label: 'Brands', path: '/brands' },
    { label: 'New Release', path: '/new-release' },
    { label: 'Limited', path: '/limited' },
    { label: 'Promo', path: '/promo' },
    { label: 'Community', path: '/community' },
  ];

  return (
    <nav className="fixed top-0 left-0 w-full z-50 px-6 py-4 lg:px-12 lg:py-6 bg-obsidian/80 backdrop-blur-xl border-b border-white/5">
      <div className="max-w-[1600px] mx-auto flex items-center justify-between">
        <Link 
          to="/" 
          className="text-2xl font-black font-orbitron tracking-tighter bg-clip-text text-transparent bg-cyber-gradient hover:opacity-80 transition-opacity"
        >
          NDRAASTEP
        </Link>

        {/* Desktop Menu */}
        <div className="hidden lg:flex items-center gap-8">
          {menuItems.map((item) => (
            <NavLink
              key={item.path}
              to={item.path}
              className={({ isActive }) => `
                relative font-orbitron text-[10px] uppercase tracking-[0.2em] font-bold py-2
                ${isActive ? 'text-cyan-400' : 'text-gray-400 hover:text-white transition-colors'}
              `}
            >
              {({ isActive }) => (
                <>
                  {item.label}
                  {isActive && (
                    <motion.div
                      layoutId="nav-underline"
                      className="absolute bottom-0 left-0 w-full h-[2px] bg-cyan-400 shadow-[0_0_8px_rgba(34,211,238,0.8)]"
                      transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
                    />
                  )}
                </>
              )}
            </NavLink>
          ))}
        </div>

        {/* Action Icons */}
        <div className="flex items-center gap-6">
          <button className="text-gray-400 hover:text-white transition-colors">
            <Search size={20} strokeWidth={1.5} />
          </button>
          <button className="text-gray-400 hover:text-white transition-colors">
            <User size={20} strokeWidth={1.5} />
          </button>
          <button 
            onClick={onCartOpen}
            className="group relative flex items-center justify-center p-2 rounded-full bg-white/5 hover:bg-white/10 border border-white/10 transition-all active:scale-95"
          >
            <ShoppingCart size={20} strokeWidth={1.5} className="text-gray-400 group-hover:text-cyan-400 transition-colors" />
            <AnimatePresence>
              {cartCount > 0 && (
                <motion.span 
                  initial={{ scale: 0 }}
                  animate={{ scale: 1 }}
                  exit={{ scale: 0 }}
                  className="absolute -top-1 -right-1 w-5 h-5 bg-cyan-500 text-white text-[10px] font-bold font-orbitron rounded-full flex items-center justify-center shadow-lg shadow-cyan-500/30"
                >
                  {cartCount}
                </motion.span>
              )}
            </AnimatePresence>
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

import React from 'react';
import { motion } from 'framer-motion';
import { ShoppingCart, Heart, ArrowUpRight } from 'lucide-react';
import { Product } from '../types';

interface ProductCardProps {
  product: Product;
  onAddToCart: (p: Product) => void;
}

const ProductCard: React.FC<ProductCardProps> = ({ product, onAddToCart }) => {
  return (
    <motion.div 
      whileHover={{ y: -10 }}
      className="group relative bg-[#0a0a0a] border border-white/5 rounded-2xl overflow-hidden"
    >
      {/* Background Decorative Element */}
      <div className="absolute top-0 right-0 w-32 h-32 bg-cyan-500/5 blur-[60px] rounded-full -mr-16 -mt-16 group-hover:bg-cyan-500/10 transition-colors" />

      {/* Image Wrapper */}
      <div className="relative aspect-square overflow-hidden p-6">
        {product.limited && (
          <div className="absolute top-4 left-4 z-10 px-2 py-1 bg-cyan-500 text-obsidian text-[8px] font-black font-orbitron uppercase tracking-widest rounded">
            LIMITED EDITION
          </div>
        )}
        <img 
          src={product.image} 
          alt={product.name} 
          className="w-full h-full object-contain group-hover:scale-110 transition-transform duration-700 ease-out"
        />

        {/* Quick Actions Overlay */}
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-center justify-center gap-3">
          <motion.button 
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
            className="w-12 h-12 bg-white text-black rounded-full flex items-center justify-center shadow-xl"
            onClick={() => onAddToCart(product)}
          >
            <ShoppingCart size={20} />
          </motion.button>
          <motion.button 
            whileHover={{ scale: 1.1 }}
            whileTap={{ scale: 0.9 }}
            className="w-12 h-12 bg-black/60 text-white rounded-full flex items-center justify-center backdrop-blur-md border border-white/20 shadow-xl"
          >
            <Heart size={20} />
          </motion.button>
        </div>
      </div>

      {/* Info */}
      <div className="p-6 pt-0 space-y-2">
        <div className="flex justify-between items-start">
          <div>
            <p className="text-[10px] font-orbitron font-bold text-gray-500 uppercase tracking-widest">{product.brand}</p>
            <h3 className="text-lg font-bold text-white group-hover:text-cyan-400 transition-colors truncate pr-2">{product.name}</h3>
          </div>
          <p className="font-orbitron font-bold text-cyan-500 text-lg">${product.price}</p>
        </div>
        <p className="text-xs text-gray-400 line-clamp-1">{product.description}</p>

        <div className="pt-4 flex items-center justify-between">
          <button className="text-[10px] font-orbitron font-black text-gray-500 hover:text-white flex items-center gap-1 transition-colors uppercase tracking-widest">
            View Protocol <ArrowUpRight size={14} />
          </button>
          <div className="flex gap-1">
            <div className="w-1.5 h-1.5 rounded-full bg-white/10" />
            <div className="w-1.5 h-1.5 rounded-full bg-cyan-500" />
            <div className="w-1.5 h-1.5 rounded-full bg-white/10" />
          </div>
        </div>
      </div>

      {/* Corner Accent */}
      <div className="absolute bottom-0 right-0 w-8 h-8 opacity-20 border-r-2 border-b-2 border-cyan-500 rounded-br-2xl translate-x-1 translate-y-1 group-hover:translate-x-0 group-hover:translate-y-0 transition-transform" />
    </motion.div>
  );
};

export default ProductCard;

import React from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { X, Trash2, Plus, Minus, CreditCard } from 'lucide-react';
import { CartItem } from '../types';

interface CartDrawerProps {
  isOpen: boolean;
  onClose: () => void;
  items: CartItem[];
  onRemove: (id: string) => void;
  onUpdateQuantity: (id: string, delta: number) => void;
}

const CartDrawer: React.FC<CartDrawerProps> = ({ isOpen, onClose, items, onRemove, onUpdateQuantity }) => {
  const total = items.reduce((sum, item) => sum + item.price * item.quantity, 0);

  return (
    <AnimatePresence>
      {isOpen && (
        <>
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[100]"
          />
          <motion.div 
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="fixed top-0 right-0 h-full w-full sm:w-[450px] bg-[#080808] border-l border-white/10 z-[101] shadow-2xl flex flex-col"
          >
            {/* Header */}
            <div className="p-6 border-b border-white/5 flex items-center justify-between bg-white/2">
              <h2 className="text-xl font-orbitron font-black tracking-tight flex items-center gap-3">
                SECURE CART <span className="text-[10px] px-2 py-0.5 bg-cyan-500/20 text-cyan-400 border border-cyan-500/30 rounded">ENCRYPTED</span>
              </h2>
              <button onClick={onClose} className="p-2 hover:bg-white/5 rounded-full transition-colors text-gray-400">
                <X size={24} />
              </button>
            </div>

            {/* Items */}
            <div className="flex-1 overflow-y-auto p-6 space-y-6">
              {items.length === 0 ? (
                <div className="h-full flex flex-col items-center justify-center space-y-4 opacity-30">
                  <div className="w-16 h-16 border-2 border-dashed border-white rounded-full flex items-center justify-center">
                    <Trash2 size={24} />
                  </div>
                  <p className="font-orbitron text-xs tracking-[0.2em]">CART EMPTY. AWAITING DATA...</p>
                </div>
              ) : (
                <AnimatePresence initial={false}>
                  {items.map(item => (
                    <motion.div 
                      key={item.id}
                      initial={{ opacity: 0, x: 20 }}
                      animate={{ opacity: 1, x: 0 }}
                      exit={{ opacity: 0, scale: 0.9 }}
                      className="flex gap-4 group"
                    >
                      <div className="w-24 h-24 bg-white/5 border border-white/10 rounded-lg overflow-hidden flex-shrink-0">
                        <img src={item.image} alt={item.name} className="w-full h-full object-contain p-2" />
                      </div>
                      <div className="flex-1 flex flex-col justify-between">
                        <div>
                          <div className="flex justify-between">
                            <h3 className="font-bold text-sm text-white">{item.name}</h3>
                            <button onClick={() => onRemove(item.id)} className="text-gray-500 hover:text-red-500 transition-colors">
                              <Trash2 size={16} />
                            </button>
                          </div>
                          <p className="text-[10px] text-gray-500 uppercase tracking-widest">{item.brand}</p>
                        </div>
                        <div className="flex justify-between items-end">
                          <div className="flex items-center gap-3 bg-white/5 rounded-md px-2 py-1 border border-white/10">
                            <button onClick={() => onUpdateQuantity(item.id, -1)} className="p-1 hover:text-cyan-400 transition-colors">
                              <Minus size={14} />
                            </button>
                            <span className="text-xs font-orbitron w-4 text-center">{item.quantity}</span>
                            <button onClick={() => onUpdateQuantity(item.id, 1)} className="p-1 hover:text-cyan-400 transition-colors">
                              <Plus size={14} />
                            </button>
                          </div>
                          <p className="font-orbitron font-bold text-cyan-400">${item.price * item.quantity}</p>
                        </div>
                      </div>
                    </motion.div>
                  ))}
                </AnimatePresence>
              )}
            </div>

            {/* Footer */}
            {items.length > 0 && (
              <div className="p-6 bg-white/5 border-t border-white/5 space-y-4">
                <div className="space-y-2">
                  <div className="flex justify-between text-sm text-gray-400">
                    <span>Subtotal</span>
                    <span className="font-orbitron font-bold text-white">${total}</span>
                  </div>
                  <div className="flex justify-between text-sm text-gray-400">
                    <span>Shipping</span>
                    <span className="text-cyan-400 font-bold uppercase text-[10px] tracking-widest">Calculated at Checkout</span>
                  </div>
                  <div className="h-px bg-white/10 my-4" />
                  <div className="flex justify-between items-center">
                    <span className="text-lg font-orbitron font-bold">TOTAL</span>
                    <span className="text-2xl font-orbitron font-black text-cyan-400">${total}</span>
                  </div>
                </div>
                <button className="w-full bg-cyan-500 hover:bg-cyan-400 text-obsidian font-orbitron font-black py-4 rounded-xl flex items-center justify-center gap-3 transition-all active:scale-[0.98]">
                  <CreditCard size={20} />
                  PROCESS CHECKOUT
                </button>
                <p className="text-[8px] text-center text-gray-600 font-orbitron tracking-widest uppercase">
                  All transactions secured by quantum-shield encryption
                </p>
              </div>
            )}
          </motion.div>
        </>
      )}
    </AnimatePresence>
  );
};

export default CartDrawer;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { Filter, ChevronDown, LayoutGrid, List } from 'lucide-react';
import ProductCard from '../components/ProductCard';
import { PRODUCTS } from '../data';
import { Product } from '../types';

interface ShopProps {
  onAddToCart: (p: Product) => void;
  filterLimited?: boolean;
}

const Shop: React.FC<ShopProps> = ({ onAddToCart, filterLimited }) => {
  const [activeCategory, setActiveCategory] = useState<string>('All');
  const [activeBrand, setActiveBrand] = useState<string>('All');

  const categories = ['All', 'Men', 'Women', 'Unisex'];
  const brands = ['All', 'Nike', 'Adidas', 'Puma', 'New Balance'];

  const filteredProducts = PRODUCTS.filter(p => {
    const matchesLimited = filterLimited ? p.limited : true;
    const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
    const matchesBrand = activeBrand === 'All' || p.brand === activeBrand;
    return matchesLimited && matchesCategory && matchesBrand;
  });

  return (
    <div className="max-w-[1600px] mx-auto px-6 lg:px-20 py-12">
      {/* Page Header */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 mb-16">
        <div>
          <h1 className="text-5xl lg:text-7xl font-orbitron font-black tracking-tighter mb-4">
            {filterLimited ? 'LIMITED' : 'SHOP'} <span className="text-cyan-500">ARCHIVE</span>
          </h1>
          <p className="text-gray-500 font-orbitron text-xs tracking-widest">SHOWING {filteredProducts.length} PROTOCOLS AVAILABLE</p>
        </div>

        {/* View Toggles */}
        <div className="flex items-center gap-4">
          <button className="w-10 h-10 flex items-center justify-center bg-white/5 border border-white/10 rounded-lg text-cyan-400">
            <LayoutGrid size={20} />
          </button>
          <button className="w-10 h-10 flex items-center justify-center bg-transparent border border-white/10 rounded-lg text-gray-500 hover:text-white transition-colors">
            <List size={20} />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-12">
        {/* Filters Sidebar */}
        <aside className="lg:col-span-3 space-y-10">
          <div className="space-y-6">
            <h3 className="font-orbitron font-black text-sm tracking-widest flex items-center gap-2">
              <Filter size={16} className="text-cyan-500" /> CATEGORIES
            </h3>
            <div className="flex flex-wrap gap-2">
              {categories.map(cat => (
                <button
